/* font-data.js — встроенный шрифт тодо (TodoPozdneyev) как data-URI в JS-константе.
   ЕДИНЫЙ ИСТОЧНИК: отсюда регистрируется @font-face для отображения И отсюда же
   берётся шрифт для экспорта картинок. Это работает даже при открытии сайта как
   файла (file://), где доступ к CSS из JS заблокирован браузером.
   Подключать ПЕРВЫМ в <head>, до отрисовки глифов. */
const TODO_FONT_SRC = 'data:font/ttf;base64,';
(function () {
    try {
        var st = document.createElement('style');
        st.textContent = "@font-face{font-family:'TodoPozdneyev';src:url(" + TODO_FONT_SRC + ");font-display:block;}";
        (document.head || document.documentElement).appendChild(st);
    } catch (e) {}
})();
